//
import { Registry } from '../core/zc-registry';
import { pick } from '../utils/zcutils';
import { d3_set } from '../core/d3-constants';

var LOCATION_MARKERS = d3_set([
    'geo-location-1',
    'geo-location-2',
    'geo-location-3',
    'geo-flag-1',
    'geo-flag-2',
    'geo-flag-3',
    'geo-pin-1',
    'geo-pin-2',
    'geo-pin-3'
]);

/**
 * fetch symbol constants from registry
 * @param {*} name 
 */
function getSymbolConstants(name) {
    return Registry.getComponent('svg.symbols.constants')[name];
}

function getGeoSVGSymbol(type, size, side) {
    side = pick(side, 'outer');

    var symbols = {
        'geo-location-1': getSymbolConstants('geo-location-1')(size),
        'geo-location-2': getSymbolConstants('geo-location-2')(size),
        'geo-location-3': getSymbolConstants('geo-location-3')(size),
        'geo-pin-1': getSymbolConstants('geo-pin-1')(size),
        'geo-pin-2': getSymbolConstants('geo-pin-2')(size),
        'geo-pin-3': getSymbolConstants('geo-pin-3')(size),
        'geo-flag-1': getSymbolConstants('geo-flag-1')(size),
        'geo-flag-2': getSymbolConstants('geo-flag-2')(size),
        'geo-flag-3': getSymbolConstants('geo-flag-3')(size)
    };

    return symbols[type][side];
}

export { LOCATION_MARKERS, getGeoSVGSymbol };
Registry.setComponent('svg.symbolPath.geo', getGeoSVGSymbol);
Registry.setComponent('svg.symbols.constants', {});
